"use client";

import { useEffect, useState } from "react";
import { apiFetch } from "@/lib/api";
import { isSuperAdmin } from "@/lib/auth";
import Button from "@/components/ui/button/Button";
import { Modal } from "@/components/ui/modal";
import Badge from "@/components/ui/badge/Badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHeader,
  TableRow,
} from "@/components/ui/table";

type Merchant = {
  id: string;
  business_name_en: string;
};

type Integration = {
  id: string;
  merchant_id: string;
  name: string;
  base_url: string;
  auth_type: string;
  credit_accounts_endpoint: string;
  payments_endpoint: string;
  is_active: boolean;
  sync_interval_minutes: number;
  last_sync_at?: string | null;
  last_success_at?: string | null;
  last_error?: string | null;
};

type SyncResult = {
  merchant_id: string;
  credit_accounts_created: number;
  credit_accounts_updated: number;
  payments_created: number;
  failed_imports: number;
};

const emptyForm = {
  merchant_id: "",
  name: "default",
  base_url: "",
  auth_type: "bearer",
  api_key: "",
  credit_accounts_endpoint: "/api/credit-accounts",
  payments_endpoint: "/api/payments",
  sync_interval_minutes: 60,
};

export default function IntegrationsPage() {
  const [integrations, setIntegrations] = useState<Integration[]>([]);
  const [merchants, setMerchants] = useState<Merchant[]>([]);
  const [open, setOpen] = useState(false);
  const [previewOpen, setPreviewOpen] = useState(false);
  const [previewData, setPreviewData] = useState<any | null>(null);
  const [previewMerchantId, setPreviewMerchantId] = useState<string | null>(null);
  const [editingIntegration, setEditingIntegration] =
    useState<Integration | null>(null);
  const [form, setForm] = useState(emptyForm);
  const [loading, setLoading] = useState(false);
  const [syncingMerchantId, setSyncingMerchantId] = useState<string | null>(null);
  const [message, setMessage] = useState("");

  async function loadData() {
    setLoading(true);
    setMessage("");

    try {
      const [integrationsData, merchantsData] = await Promise.all([
        apiFetch("/admin/merchant-integrations"),
        apiFetch("/admin/merchants"),
      ]);

      setIntegrations(integrationsData);
      setMerchants(merchantsData);
    } catch (err: any) {
      setMessage(err.message || "Failed to load integrations");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    if (!isSuperAdmin()) {
      setMessage("Access denied. Super admin only.");
      return;
    }

    loadData();
  }, []);

  function resetForm() {
    setForm(emptyForm);
    setEditingIntegration(null);
  }

  function openAddModal() {
    resetForm();
    setOpen(true);
  }

  function openEditModal(item: Integration) {
    setEditingIntegration(item);
    setForm({
      merchant_id: item.merchant_id,
      name: item.name,
      base_url: item.base_url,
      auth_type: item.auth_type,
      api_key: "",
      credit_accounts_endpoint: item.credit_accounts_endpoint,
      payments_endpoint: item.payments_endpoint,
      sync_interval_minutes: item.sync_interval_minutes,
    });
    setOpen(true);
  }

  async function saveIntegration(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    setMessage("");

    const payload: any = {
      name: form.name,
      base_url: form.base_url,
      auth_type: form.auth_type,
      credit_accounts_endpoint: form.credit_accounts_endpoint,
      payments_endpoint: form.payments_endpoint,
      sync_interval_minutes: Number(form.sync_interval_minutes),
      is_active: true,
    };

    if (!editingIntegration) {
      payload.merchant_id = form.merchant_id;
    }

    if (form.auth_type !== "none" && form.api_key) {
      payload.api_key = form.api_key;
    }

    try {
      if (editingIntegration) {
        await apiFetch(`/admin/merchant-integrations/${editingIntegration.id}`, {
          method: "PATCH",
          body: JSON.stringify(payload),
        });

        setMessage("Integration updated successfully.");
      } else {
        await apiFetch("/admin/merchant-integrations", {
          method: "POST",
          body: JSON.stringify(payload),
        });

        setMessage("Integration created successfully.");
      }

      setOpen(false);
      resetForm();
      await loadData();
    } catch (err: any) {
      setMessage(err.message || "Failed to save integration");
    } finally {
      setLoading(false);
    }
  }

  async function deleteIntegration(item: Integration) {
    const confirmed = window.confirm(
      `Hard delete integration "${item.name}"? This cannot be undone.`
    );

    if (!confirmed) return;

    setLoading(true);
    setMessage("");

    try {
      await apiFetch(`/admin/merchant-integrations/${item.id}`, {
        method: "DELETE",
      });

      setMessage("Integration permanently deleted.");
      await loadData();
    } catch (err: any) {
      setMessage(err.message || "Failed to delete integration");
    } finally {
      setLoading(false);
    }
  }

  async function previewSync(merchantId: string) {
    setSyncingMerchantId(merchantId);
    setMessage("");

    try {
      const data = await apiFetch(
        `/admin/merchant-integrations/${merchantId}/preview`
      );

      setPreviewData(data);
      setPreviewMerchantId(merchantId);
      setPreviewOpen(true);
    } catch (err: any) {
      setMessage(err.message || "Preview failed");
    } finally {
      setSyncingMerchantId(null);
    }
  }

  async function uploadPreviewData() {
    if (!previewMerchantId || !previewData) return;

    setLoading(true);
    setMessage("");

    try {
      const result: SyncResult = await apiFetch(
        `/admin/merchant-integrations/${previewMerchantId}/import`,
        {
          method: "POST",
          body: JSON.stringify({
            credit_accounts: previewData.credit_accounts || [],
            payments: previewData.payments || [],
          }),
        }
      );

      setPreviewOpen(false);
      setPreviewData(null);
      setPreviewMerchantId(null);

      setMessage(
        `Upload complete: ${result.credit_accounts_created} accounts created, ${result.credit_accounts_updated} accounts updated, ${result.payments_created} payments imported, ${result.failed_imports} failed.`
      );

      await loadData();
    } catch (err: any) {
      setMessage(err.message || "Upload failed");
    } finally {
      setLoading(false);
    }
  }

  function merchantName(merchantId: string) {
    return (
      merchants.find((merchant) => merchant.id === merchantId)
        ?.business_name_en || merchantId
    );
  }

  return (
    <div>
      <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-2xl font-semibold text-gray-800 dark:text-white/90">
            إدارة موصلات API الخارجية
          </h1>
          <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
            
          </p>
        </div>

        {isSuperAdmin() && <Button onClick={openAddModal}>إضافة جديد</Button>}
      </div>

      {message && (
        <div className="mb-4 rounded-lg border border-gray-200 bg-white p-4 text-sm text-gray-700 dark:border-white/[0.05] dark:bg-white/[0.03] dark:text-gray-300">
          {message}
        </div>
      )}

      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white dark:border-white/[0.05] dark:bg-white/[0.03]">
        <div className="max-w-full overflow-x-auto">
          <Table>
            <TableHeader className="border-b border-gray-100 dark:border-white/[0.05]">
              <TableRow>
                <TableCell isHeader className="px-5 py-3 text-start">Merchant</TableCell>
                <TableCell isHeader className="px-5 py-3 text-start">Name</TableCell>
                <TableCell isHeader className="px-5 py-3 text-start">Base URL</TableCell>
                <TableCell isHeader className="px-5 py-3 text-start">Auth</TableCell>
                <TableCell isHeader className="px-5 py-3 text-start">Status</TableCell>
                <TableCell isHeader className="px-5 py-3 text-start">Last Sync</TableCell>
                <TableCell isHeader className="px-5 py-3 text-start">Actions</TableCell>
              </TableRow>
            </TableHeader>

            <TableBody className="divide-y divide-gray-100 dark:divide-white/[0.05]">
              {integrations.map((item) => (
                <TableRow key={item.id}>
                  <TableCell className="px-5 py-4">{merchantName(item.merchant_id)}</TableCell>
                  <TableCell className="px-5 py-4">{item.name}</TableCell>
                  <TableCell className="px-5 py-4">
                    <span className="break-all">{item.base_url}</span>
                  </TableCell>
                  <TableCell className="px-5 py-4">{item.auth_type}</TableCell>
                  <TableCell className="px-5 py-4">
                    <Badge color={item.is_active ? "success" : "error"}>
                      {item.is_active ? "Active" : "Inactive"}
                    </Badge>
                  </TableCell>
                  <TableCell className="px-5 py-4">
                    {item.last_sync_at
                      ? new Date(item.last_sync_at).toLocaleString()
                      : "Never"}
                  </TableCell>
                  <TableCell className="px-5 py-4">
                    <div className="flex flex-wrap gap-2">
                      <Button
                        size="sm"
                        disabled={syncingMerchantId === item.merchant_id}
                        onClick={() => previewSync(item.merchant_id)}
                      >
                        {syncingMerchantId === item.merchant_id ? "Fetching..." : "Sync Now"}
                      </Button>

                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => openEditModal(item)}
                      >
                        تعديل
                      </Button>

                      <button
                        type="button"
                        onClick={() => deleteIntegration(item)}
                        className="rounded-lg bg-red-600 px-3 py-2 text-sm font-medium text-white hover:bg-red-700 disabled:opacity-50"
                        disabled={loading}
                      >
                        حذف
                      </button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}

              {!loading && integrations.length === 0 && (
                <TableRow>
                  <TableCell className="px-5 py-6 text-gray-500">
                    No integrations found.
                  </TableCell>
                </TableRow>
              )}

              {loading && integrations.length === 0 && (
                <TableRow>
                  <TableCell className="px-5 py-6 text-gray-500">
                    Loading integrations...
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </div>
      </div>

      <Modal isOpen={open} onClose={() => setOpen(false)} className="max-w-xl">
        <form onSubmit={saveIntegration} className="p-6">
          <h2 className="mb-4 text-xl font-semibold text-gray-800 dark:text-white/90">
            {editingIntegration ? "Edit Merchant Integration" : "Add Merchant Integration"}
          </h2>

          <div className="space-y-4">
            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                Merchant
              </label>
              <select
                required
                disabled={!!editingIntegration}
                value={form.merchant_id}
                onChange={(e) => setForm({ ...form, merchant_id: e.target.value })}
                className="h-11 w-full rounded-lg border border-gray-300 px-4 text-sm disabled:bg-gray-100 dark:border-gray-700 dark:bg-gray-900 dark:text-white"
              >
                <option value="">Select merchant</option>
                {merchants.map((merchant) => (
                  <option key={merchant.id} value={merchant.id}>
                    {merchant.business_name_en}
                  </option>
                ))}
              </select>
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                Integration Name
              </label>
              <input
                required
                value={form.name}
                onChange={(e) => setForm({ ...form, name: e.target.value })}
                className="h-11 w-full rounded-lg border border-gray-300 px-4 text-sm dark:border-gray-700 dark:bg-gray-900 dark:text-white"
              />
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                External Base URL
              </label>
              <input
                required
                type="url"
                value={form.base_url}
                onChange={(e) => setForm({ ...form, base_url: e.target.value })}
                placeholder="https://merchant-system.com"
                className="h-11 w-full rounded-lg border border-gray-300 px-4 text-sm dark:border-gray-700 dark:bg-gray-900 dark:text-white"
              />
              <p className="mt-1 text-xs text-gray-500">
                Must start with http:// or https://
              </p>
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                Auth Type
              </label>
              <select
                value={form.auth_type}
                onChange={(e) => setForm({ ...form, auth_type: e.target.value })}
                className="h-11 w-full rounded-lg border border-gray-300 px-4 text-sm dark:border-gray-700 dark:bg-gray-900 dark:text-white"
              >
                <option value="bearer">Bearer Token</option>
                <option value="api_key">API Key</option>
                <option value="none">No Auth</option>
              </select>
            </div>

            {form.auth_type !== "none" && (
              <div>
                <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                  API Key / Bearer Token
                </label>
                <input
                  type="password"
                  value={form.api_key}
                  onChange={(e) => setForm({ ...form, api_key: e.target.value })}
                  placeholder={
                    editingIntegration
                      ? "Leave blank to keep existing secret"
                      : "Enter API key or bearer token"
                  }
                  className="h-11 w-full rounded-lg border border-gray-300 px-4 text-sm dark:border-gray-700 dark:bg-gray-900 dark:text-white"
                />
              </div>
            )}

            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                Credit Accounts Endpoint
              </label>
              <input
                required
                value={form.credit_accounts_endpoint}
                onChange={(e) =>
                  setForm({ ...form, credit_accounts_endpoint: e.target.value })
                }
                className="h-11 w-full rounded-lg border border-gray-300 px-4 text-sm dark:border-gray-700 dark:bg-gray-900 dark:text-white"
              />
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                Payments Endpoint
              </label>
              <input
                required
                value={form.payments_endpoint}
                onChange={(e) =>
                  setForm({ ...form, payments_endpoint: e.target.value })
                }
                className="h-11 w-full rounded-lg border border-gray-300 px-4 text-sm dark:border-gray-700 dark:bg-gray-900 dark:text-white"
              />
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                Sync Interval Minutes
              </label>
              <input
                type="number"
                min={5}
                value={form.sync_interval_minutes}
                onChange={(e) =>
                  setForm({
                    ...form,
                    sync_interval_minutes: Number(e.target.value),
                  })
                }
                className="h-11 w-full rounded-lg border border-gray-300 px-4 text-sm dark:border-gray-700 dark:bg-gray-900 dark:text-white"
              />
            </div>
          </div>

          <div className="mt-6 flex justify-end gap-3">
            <Button variant="outline" type="button" onClick={() => setOpen(false)}>
              Cancel
            </Button>

            <Button type="submit" disabled={loading}>
              {loading
                ? "Saving..."
                : editingIntegration
                  ? "Update Integration"
                  : "Save Integration"}
            </Button>
          </div>
        </form>
      </Modal>

      <Modal
        isOpen={previewOpen}
        onClose={() => setPreviewOpen(false)}
        className="max-w-5xl"
      >
        <div className="p-6">
          <h2 className="mb-4 text-xl font-semibold text-gray-800 dark:text-white/90">
            Verify External API Data
          </h2>

          <div className="mb-4 grid grid-cols-1 gap-4 sm:grid-cols-3">
            <div className="rounded-lg border border-gray-200 p-4 dark:border-gray-700">
              <p className="text-xs text-gray-500">Credit accounts</p>
              <p className="text-xl font-semibold text-gray-800 dark:text-white">
                {previewData?.credit_accounts?.length || 0}
              </p>
            </div>

            <div className="rounded-lg border border-gray-200 p-4 dark:border-gray-700">
              <p className="text-xs text-gray-500">Payments</p>
              <p className="text-xl font-semibold text-gray-800 dark:text-white">
                {previewData?.payments?.length || 0}
              </p>
            </div>

            <div className="rounded-lg border border-gray-200 p-4 dark:border-gray-700">
              <p className="text-xs text-gray-500">Merchant ID</p>
              <p className="break-all text-sm font-medium text-gray-800 dark:text-white">
                {previewMerchantId}
              </p>
            </div>
          </div>

          <div className="max-h-[500px] overflow-auto rounded-lg border border-gray-200 bg-gray-50 p-4 dark:border-gray-700 dark:bg-gray-900">
            <pre className="whitespace-pre-wrap text-xs text-gray-800 dark:text-gray-200">
              {JSON.stringify(previewData, null, 2)}
            </pre>
          </div>

          <div className="mt-6 flex justify-end gap-3">
            <Button variant="outline" type="button" onClick={() => setPreviewOpen(false)}>
              Cancel
            </Button>

            <Button
              type="button"
              onClick={uploadPreviewData}
              disabled={!previewMerchantId || !previewData || loading}
            >
              {loading ? "Uploading..." : "Upload to Database"}
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  );
}